inner.emit(event);\n    82\t            }\n    83\t            LoopAuditEvent::ToolCallRequested { tool_name, .. }\n    84\t                if !tool_allowed(tool_name, &self.allowlist) =>\n    85\t            {\n    86\t                let reason = format!(\"tool `{tool_name}` not in allowlist\");\n    87\t                let _ = self.writer.emit(V2AuditEventKind::ToolDenied {\n    88\t                    tool_name: tool_name.clone(),\n    89\t                    reason: reason.clone(),\n    90\t                });\n    91\t                self.inner.emit(event);\n    92\t                let denial = LoopAuditEvent::PolicyDenial {\n    93\t                    ts: chrono::Utc::now(),\n    94\t                    run_id: self.run_id.clone(),\n    95\t                    session_id: self.session_id.clone(),\n    96\t                    iteration: 0,\n    97\t                    tool_name: tool_name.clone(),\n    98\t                    reason: reason.clone(),\n    99\t                };\n   100\t                self.inner.emit(&denial);\n   101\t                *self.tripped.lock().expect(\"tripped mutex\") = Some(EnforcementDecision::Denied {\n   102\t                    tool_name: tool_name.clone(),\n   103\t                    reason,\n   104\t                });\n   105\t            }\n   106\t            _ => self.inner.emit(event),\n   107\t        }\n   108\t    }\n   109\t\n   110\t    fn write_blob(&self, content: &[u8]) -> String {\n","exit_code":0,"status":"completed"}}
