        iteration,
        tool_name: tool_name.clone(),
        reason,
    });
    iter_denials.push(tool_name.clone());
    sink.emit(&LoopAuditEvent::IterationBoundary {
        ts: Utc::now(),
        run_id: cfg.run_id.clone(),
        session_id: session.id().to_string(),
        iteration,
        continues: false,
    });
    trace.push(IterationTrace {
        iteration,
        stop_reason,
        tool_calls: iter_tool_names,
        policy_denials: iter_denials,
        usage: usage.clone(),
    });
    return Err(AgentLoopError::PolicyDenied {
        tool_name,
        iteration,
    });
}

let input_bytes = serde_json::to_vec(&input).unwrap_or_default();
let input_sha256 = sink.write_blob(&input_bytes);
sink.emit(&LoopAuditEvent::ToolCallRequested {
    ts: Utc::now(),
    run_id: cfg.run_id.clone(),
    session_id: session.id().to_string(),
    iteration,
    tool_name: tool_name.clone(),
    tool_use_id: tool_use_id.clone(),
    input_sha256,
});

let outcome = dispatch(registry, tool_ctx, &tool_name, input);
let output_bytes = serde_json::to_vec(&outcome.output).unwrap_or_default();
let output_sha256 = sink.write_blob(&output_bytes);
sink.emit(&LoopAuditEvent::ToolCallResult {
    ts: Utc::now(),
    run_id: cfg.run_id.clone(),
    session_id: session.id().to_string(),
    iteration,
    tool_name: tool_name.clone(),
    tool_use_id: tool_use_id.clone(),
    outcome: if outcome.is_error {
        "error".to_string()
    } else {
        "ok".to_string()
    },
    output_sha256,
    duration_ms: outcome.duration_ms,
});

let tool_text = match serde_json::to_string(&outcome.output) {
    Ok(s) => s,
    Err(err) => format!("{{\"error\":\"serialize: {err}\"}}"),
};
user_tool_results.push(ContentBlock::ToolResult {
    tool_use_id,
    content: tool_text,
    is_error: outcome.is_error,

        .collect();
    if iter_starts.len() < 2 {
        return Err(format!(
            "expected >=2 loop.iteration.start events, got {}",
            iter_starts.len()
        ));
    }
    let iter_ends: Vec<_> = events
        .iter()
        .filter(|e| e.envelope.event_type == "loop.iteration.end")
        .collect();
    let broke = iter_ends.iter().any(|e| {
        matches!(
            &e.kind,
            V2AuditEventKind::LoopIterationEnd { broke, .. } if *broke
        )
    });
    if !broke {
        return Err("no loop.iteration.end reported broke=true".into());
    }

    // Session persistence: every tool.call.* from loop_events should share
    // the same session_id across iterations.
    let session_ids: Vec<String> = loop_events
        .iter()
        .filter_map(|e| match e {
            LoopAuditEvent::ToolCallRequested { session_id, .. } => Some(session_id.clone()),
            LoopAuditEvent::ToolCallResult { session_id, .. } => Some(session_id.clone()),
            _ => None,
        })
        .collect();
    if session_ids.len() < 2 {
        return Err(format!(
            "expected >=2 tool.call.* events (one per iteration), got {}",
            session_ids.len()
        ));
    }
    let first = &session_ids[0];
    if !session_ids.iter().all(|s| s == first) {
        return Err(format!(
            "session_id varies across iterations: {session_ids:?}"
        ));
    }
    Ok(())
}

fn smoke_loop_diverge(samples: &Path, audit_root: &Path) -> Result<(), String> {
    let events = run_sample(
        samples.join("loop_no_converge.yaml"),
        audit_root,
        "loop-diverge",

    //    a `ToolCallRequested` event and emits its own `PolicyDenial`.
    //    When we see a `PolicyDenial`, we mirror it into a §7
    //    `tool.denied` envelope event so the higher-level trail records
    //    the policy outcome alongside the loop-level event.
    //
    // 2. A caller that bypasses the loop's own check could still emit a
    //    `ToolCallRequested` for a tool we shouldn't allow — we catch
    //    that here too and synthesize both a §7 `tool.denied` envelope
    //    event and a loop-level `PolicyDenial`.
    match event {
        LoopAuditEvent::PolicyDenial {
            tool_name, reason, ..
        } => {
            let _ = self.writer.emit(V2AuditEventKind::ToolDenied {
                tool_name: tool_name.clone(),
                reason: reason.clone(),
            });
            *self.tripped.lock().expect("tripped mutex") = Some(EnforcementDecision::Denied {
                tool_name: tool_name.clone(),
                reason: reason.clone(),
            });
            self.inner.emit(event);
        }
        LoopAuditEvent::ToolCallRequested { tool_name, .. }
            if !tool_allowed(tool_name, &self.allowlist) =>
        {
            let reason = format!("tool `{tool_name}` not in allowlist");
            let _ = self.writer.emit(V2AuditEventKind::ToolDenied {
                tool_name: tool_name.clone(),
                reason: reason.clone(),
            });
            self.inner.emit(event);
            let denial = LoopAuditEvent::PolicyDenial {
                ts: chrono::Utc::now(),
                run_id: self.run_id.clone(),
                session_id: self.session_id.clone(),
                iteration: 0,
                tool_name: tool_name.clone(),
                reason: reason.clone(),
            };
            self.inner.emit(&denial);
            *self.tripped.lock().expect("tripped mutex") = Some(EnforcementDecision::Denied {
                tool_name: tool_name.clone(),
                reason,
            });
        }
        _ => self.inner.emit(event),
    }
}

